progName = "Cadastraitor"

def hasOnlyNumbers(string):
	hasOnlyNumbers = True
	for char in string :
		if not char.isdigit() :
			hasOnlyNumbers = False
			
	if hasOnlyNumbers and string != "":
		return True
	return False
	
class App :

	def loadData(self):
	
		global progName
	
		config = cp.ConfigParser()
		
		try:
			config.read("config.ini")
			user = config.get("data", "login")
			passwEncrypted = config.get("data", "passw")
			sei = config.get("data", "SEI")
			progName = config.get("program", "name")
		except:
			tkmb.Message(self.root, message="Problema com o arquivo INI.\nTerminando execução.", type=tkmb.OK, icon=tkmb.ERROR, title="ERRO DE CONFIGURAÇÃO").show()		
			quit()
			return None
	
		self.SEI.set(sei)
		self.user.set(user)
	
		key = b"70F3T4GCnMSIfkA3aSydw28BIzSDO9YUXs30Wc0-034="
		fernet = Fernet(key)
		if passwEncrypted != "":
			passwDecrypted = fernet.decrypt(passwEncrypted).decode("utf-8")
			self.passw.set(passwDecrypted)

	def saveData(self):
		
		key = b"70F3T4GCnMSIfkA3aSydw28BIzSDO9YUXs30Wc0-034="
		fernet = Fernet(key)
		passwEncrypted = fernet.encrypt(self.passw.get().encode("utf-8")).decode("utf-8")
		
		config = cp.ConfigParser()
		config.read("data.ini")
		config["program"] = { "name" : progName }
		config["data"] = { "login": self.user.get(), "passw": passwEncrypted, "SEI" : self.SEI.get()}

		file = open("config.ini", "w")
		config.write(file)

	def message(self, text):
		tkmb.Message(self.root, message=text, type=tkmb.OK, icon=tkmb.WARNING).show()

	def erasePNGfiles(self):
		
		for file in os.listdir() : 
			if file.endswith('.png') and file != "noface.png" :
				print("deleting " + file)
				os.remove(file)

	def showImage(self):
		try:
			im = Image.open(self.alunos[self.i].RA.get() + ".png")
			im.show()
		except:
			print("failure to open image")
	
	def beep(self, freq=500, duration=100):
		winsound.Beep(freq, duration)
	
	def getAuth(self):
		
		class AuthData:
			def __init__(self):
				self.username = None
				self.password = None
		
		auth = AuthData()
		auth.username = self.user.get()
		auth.password = self.passw.get()
		return auth
	
	def loadNotes(self):
		
		try:
			file = open("notas.txt", "r")
			notes = file.read()
			file.close()
			
			notes = notes[:-1]
			self.notasText.insert("1.0", notes)
		except:
			pass
		
	def saveNotes(self):
		file = open("notas.txt", "w")
		file.write( self.notasText.get("1.0", "end") )
		file.close()
	
	def saveSEI(self):
		file = open("sei.data", "w")
		file.write(self.SEI.get())
		file.close()
	
	def loadSEI(self):
		try:
			file = open("sei.data", "r")
			self.SEI.set(file.read())
			file.close()
		except:
			pass
	
	def loadUserAndPass(self):
		
		try:
		
			file = open("user.data")
			userToken = file.readline()
			passwToken = file.readline()
			file.close()
			
			key = b"70F3T4GCnMSIfkA3aSydw28BIzSDO9YUXs30Wc0-034="
			fernet = Fernet(key)
			unUserToken = fernet.decrypt(userToken)
			unPasswToken = fernet.decrypt(passwToken)
			
			self.user.set(unUserToken.decode("utf-8"))
			self.passw.set(unPasswToken.decode("utf-8"))
			
		except:
			pass
		
	def saveUserAndPass(self):
	
		key = b"70F3T4GCnMSIfkA3aSydw28BIzSDO9YUXs30Wc0-034="
		fernet = Fernet(key)
		userToken = fernet.encrypt(self.user.get().encode("utf-8"))
		passwToken = fernet.encrypt(self.passw.get().encode("utf-8"))
		
		file = open("user.data", "w")
		file.write(userToken.decode("utf-8"))
		file.write("\n")
		file.write(passwToken.decode("utf-8"))
		file.close()
	
	def addRA(self, string=""):
		
		if(self.ra.get() != "" and hasOnlyNumbers(self.ra.get()) ):
			self.raListbox.insert("end", self.ra.get())
			self.ra.set("")
			self.raEntry.focus_set()
			self.raListbox.see(self.raListbox.size()-1)
		else:
			tkmb.Message(self.root, message="RAs devem conter apenas números.", title="Falha em \"" + self.ra.get() + "\"", type=tkmb.OK, icon=tkmb.ERROR).show()
		
	def subtractRA(self, string=""):
	
		selected = self.raListbox.curselection()
		if(len(selected) > 0):
			self.raListbox.delete(selected[0])
		
		selected = self.specialRAListbox.curselection()
		if(len(selected) > 0):
			self.specialRAListbox.delete(selected[0])
	
	def loadPrev(self):
		self.i = self.i - 1
		if self.i < 0:
			self.i = len(self.alunos)-1
			self.beep()
			
		self.loadAlunoAtVerificacao(self.alunos, self.i)
		
	def loadNext(self):
		self.i = self.i + 1
		if self.i >= len(self.alunos):
			self.i = 0
			self.beep()
		self.loadAlunoAtVerificacao(self.alunos, self.i)
	
	def getFromClipboard(self):
		
		try:
			longStr = self.root.clipboard_get()
			
			splitted = longStr.split("\n")
			
			for ra in splitted :
				if hasOnlyNumbers(ra):
					self.raListbox.insert("end", ra)
					self.raListbox.see(self.raListbox.size()-1)
				else:
					tkmb.Message(self.root, message="RAs devem conter apenas números.", title="Falha em \"" + ra + "\"", type=tkmb.OK, icon=tkmb.ERROR).show()
		except:
			print("clipboard failure")

	def report(self):
		for aluno in self.alunos:
			self.relatorioText.insert("end", aluno.getStr())

	def avisoLicenca(self):
		s = progName
		s = s + " -- Criador de Processos de Transferência de Carga Patrimonial no SEI.\n\n"
		s = s + "Este programa é software livre; você pode redistribuí-lo e/ou modificá-lo sob "
		s = s + "os termos da Licença Pública Geral GNU, conforme publicada pela Free Software "
		s = s + "Foundation.\n\n"
		s = s + "Este programa é distribuído na expectativa de ser útil, mas SEM QUALQUER "
		s = s + "GARANTIA; incluindo as garantias implícitas de COMERCIALIZAÇÃO ou de ADEQUAÇÃO "
		s = s + "A QUALQUER PROPÓSITO EM PARTICULAR. Consulte a Licença Pública Geral GNU para "
		s = s + "obter mais detalhes.\n\n"
		s = s + "Você deve ter recebido uma cópia da Licença Pública Geral GNU (\""
		s = s + "Licenca Publica Geral GNU.txt\") em conjunto com este programa; "
		s = s + "caso contrário, entre no site:\n https://www.gnu.org/licenses/gpl-2.0.en.html.\n\n"
		s = s + "Leonardo Weiss Ribeiro,\n"
		s = s + "Autor do "
		s = s + progName.split(" ")[0]
		return s

	def process(self):
	
		answer = tkmb.Message(self.root, message="Tem certeza que deseja iniciar o processo?", type=tkmb.YESNO, icon=tkmb.QUESTION).show()
		
		# possibilidades para aluno.status
		# DESCONHECIDO <- houve algum erro, não faça nada!
		# INEXISTENTE <- não faça nada!
		# INFO COLETADA <- faça o cadastro normalmente.
		# ATIVO <- não faça nada!
		# INATIVO <- ative
			# clicar em "Reativar Usuário Externo" e depois em "OK"
		# ATIVO E PENDENTE <- ative
			# clique em "Alterar Usuário Externo", depois no checkbutton "Liberado", depois no botão "Salvar"
		# INATIVO E PENDENTE
			# clicar em "Reativar Usuário Externo", depois em "OK", daí então
			# clique em "Alterar Usuário Externo", depois no checkbutton "Liberado", depois no botão "Salvar"
		
		if answer == tkmb.YES :
			self.bot.processarCadastros(self.alunos, self.SEI.get(), self.passw.get())
			self.report()
			
			tkmb.Message(self.root, message="Processo completado!", type=tkmb.OK, icon=tkmb.INFO).show()
	
	def collect(self):
		
		if self.SEI.get() == "" :
			tkmb.Message(self.root, message="Processo SEI não especificado.", type=tkmb.OK, icon=tkmb.WARNING).show()
			return None
		
		raList = self.raListbox.get(0, "end")
		specialRAList = self.specialRAListbox.get(0, "end")
	
		if (self.raListbox.size() + self.specialRAListbox.size()) == 0:
			tkmb.Message(self.root, message="Nenhum RA especificado.", type=tkmb.OK, icon=tkmb.WARNING).show()
			return None
		
		
		# initializing PROCESSAMENTO...
		self.i = 0
		self.alunos.clear()
		self.relatorioText.delete('1.0', "end")	
		self.coletarButton.config(text="COLETANDO...")
		self.notebook.tab(2, state="disabled")
		self.root.update()
		self.erasePNGfiles()
		
		if self.bot is None:
			self.bot = Robot()
			self.bot.getAuth = self.getAuth
			

		# the order of those next 4 lines matter! don't mess with it
		if len(raList) > 0:
			self.alunos = self.bot.getStatusAlunos_REGULAR(raList)
		
		if len(specialRAList) > 0:
			self.alunos = self.alunos + self.bot.getStatusAlunos_ESPECIAL(specialRAList, self)
		
		# returning to normal execution, avaliate if PROCESSAR button makes sense
		self.coletarButton.config(text="COLETAR DADOS")
		
		self.report()
		
		for aluno in self.alunos:
			if aluno.hasPic:
				aluno.facePic = ImageTk.PhotoImage(Image.open(aluno.RA.get() + "face.png"))
		
		if len(self.alunos) > 0:
			self.loadAlunoAtVerificacao(self.alunos, self.i)
			self.notebook.tab(2, state="normal")
		
		'''
		count = 0
		for aluno in self.alunos :
			if not (aluno.status == "INEXISTENTE" or aluno.status == "DESCONHECIDO" or aluno.status == "ATIVO"):
				count = count + 1
				break
				
		if count == 0:
			self.procButton.config(state = "disabled")
		else:
			self.procButton.config(state = "enabled")
		'''
		
		tkmb.Message(self.root, message="Informações Coletadas!", type=tkmb.OK, icon=tkmb.INFO).show()

	def loadAlunoAtVerificacao(self, alunos, index):

		try :

			aluno = alunos[index]

			self.nomeEntry.config(textvariable=aluno.nome)
			self.nomeSocialEntry.config(textvariable=aluno.nomeSocial)
			self.CPFEntry.config(textvariable=aluno.CPF)
			self.RGEntry.config(textvariable=aluno.RG)
			self.orgaoExpedidorEntry.config(textvariable=aluno.SSP)
			self.telefoneComercialEntry.config(textvariable=aluno.telefoneComercial)
			self.telefoneCelularEntry.config(textvariable=aluno.telefoneCelular)
			self.telefoneResidencialEntry.config(textvariable=aluno.telefoneResidencial)
			self.enderecoEntry.config(textvariable=aluno.endereco)
			self.complementoEntry.config(textvariable=aluno.complemento)
			self.bairroEntry.config(textvariable=aluno.bairro)
			self.paisEntry.config(textvariable=aluno.pais)
			self.estadoEntry.config(textvariable=aluno.UF)
			self.cidadeEntry.config(textvariable=aluno.cidade)
			self.CEPEntry.config(textvariable=aluno.CEP)
			self.emailEntry.config(textvariable=aluno.email)
			self.estrangeiroCheck.config(variable=aluno.estrangeiro)
			
			if aluno.hasPic :
				self.photoLabel.config(image=aluno.facePic)
			else:
				self.photoLabel.config(image=self.noFace)
			
			string = str(index+1) + "/" + str(len(alunos))
			self.positionLabel.config(text=string)
			
			self.cadastrarCheck.config(variable=aluno.cadastrar)
			
			if aluno.status == "INEXISTENTE" or aluno.status == "DESCONHECIDO" or aluno.status == "ATIVO":
				self.cadastrarCheck.config(state = "disabled")
			else:
				self.cadastrarCheck.config(state = "enabled")
			
			self.RALabel.config(text="RA: " + aluno.RA.get())
			self.StatusLabel.config(text="STATUS: " + aluno.status)
			
		except:
			print("index out of range")
	
	def onStartup(self):
		self.loadData()
		self.loadNotes()
		self.root.title(progName)
	
	def onExit(self):
		
		self.saveNotes()
		self.saveData()
		self.erasePNGfiles()
	
		self.root.destroy()
		print("finished!")
	
	def regularToSpecial(self):
		selected = self.raListbox.curselection()
		if(len(selected) > 0):
			self.specialRAListbox.insert("end", self.raListbox.get(selected[0]))
			self.raListbox.delete(selected[0])
			self.specialRAListbox.see("end")
		
	def specialToRegular(self):
		selected = self.specialRAListbox.curselection()
		if(len(selected) > 0):
			self.raListbox.insert("end", self.specialRAListbox.get(selected[0]))
			self.specialRAListbox.delete(selected[0])
			self.raListbox.see("end")
	
	def pesquisar(self, string=""):
		
		if self.stringBusca.get() == "":
			self.buscaIndex = "0.1"
			self.notasText.tag_delete("selecao")
		else:
			count = tk.IntVar()
			noCase = not self.caseSensitiveBV.get()
			busca = self.notasText.search(pattern=self.stringBusca.get(), index=self.buscaIndex, count=count, nocase=noCase)
			self.notasText.tag_delete("selecao")
			
			if busca != "" :
				self.buscaIndex = busca + " + 1 chars"
				self.notasText.tag_add("selecao", busca, busca + " + " + str(count.get()) + " chars")
				self.notasText.tag_config("selecao", background="blue", foreground="white")
				self.notasText.see(busca)
			else:
				self.message("Nada encontrado.")

	def deleteSelecaoTag(self, event=""):
		try:
			self.notasText.tag_delete("selecao")
		except:
			pass

